      "content": "// src/server.js
const http = require('node:http');
const fs = require('node:fs');
const path = require('node:path');
const crypto = require('node:crypto');
const { existsSync } = require('node:fs');

function createServer({ dataPath }) {
  const server = http.createServer((req, res) => {
    let body = '';
    req.on('data', chunk => {
      body += chunk.toString();
    });

    req.on('end', async () => {
      if (req.url === '/health' && req.method === 'GET') {
        res.writeHead(200, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ ok: true }));
      } else if (req.url === '/openapi.json' && req.method === 'GET') {
        const openApiSpec = JSON.parse(fs.readFileSync(path.join(__dirname, '../openapi.json'), 'utf8'));
        res.writeHead(200, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify(openApiSpec));
      } else if (req.url === '/todos' && req.method === 'GET') {
        const data = existsSync(dataPath) ? JSON.parse(fs.readFileSync(dataPath, 'utf8')) : { todos: [] };
        res.writeHead(200, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ ok: true, todos: data.todos }));
      } else if (req.url === '/todos' && req.method === 'POST') {
        const todo = JSON.parse(body);
        if (!todo.title) {
          res.writeHead(400, { 'Content-Type': 'application/json' });
          return res.end(JSON.stringify({ ok: false, error: 'Title is required' }));
        }
        const newTodo = {
          id: crypto.randomUUID(),
          title: todo.title,
          done: false,
          createdAt: new Date().toISOString()
        };
        let data = existsSync(dataPath) ? JSON.parse(fs.readFileSync(dataPath, 'utf8')) : { todos: [] };
        data.todos.push(newTodo);
        fs.writeFileSync(dataPath, JSON.stringify(data));
        res.writeHead(201, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ ok: true, todo: newTodo }));
      } else if (req.url.match(/^\/todos\/(.*)$/) && req.method === 'GET') {
        const id = req.url.split('/')[2];
        const data = existsSync(dataPath) ? JSON.parse(fs.readFileSync(dataPath, 'utf8')) : { todos: [] };
        const todo = data.todos.find(t => t.id === id);
        if (todo) {
          res.writeHead(200, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify({ ok: true, todo }));
        } else {
          res.writeHead(404, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify({ ok: false, error: 'Todo not found' }));
        }
      } else if (req.url.match(/^\/todos\/(.*)$/) && req.method === 'PATCH') {
        const id = req.url.split('/')[2];
        const update = JSON.parse(body);
        let data = existsSync(dataPath) ? JSON.parse(fs.readFileSync(dataPath, 'utf8')) : { todos: [] };
        const todoIndex = data.todos.findIndex(t => t.id === id);
        if (todoIndex !== -1) {
          const updatedTodo = { ...data.todos[todoIndex], ...update };
          if (updatedTodo.done && !data.todos[todoIndex].done) {
            updatedTodo.doneAt = new Date().toISOString();
          }
          data.todos[todoIndex] = updatedTodo;
          fs.writeFileSync(dataPath, JSON.stringify(data));
          res.writeHead(200, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify({ ok: true, todo: updatedTodo }));
        } else {
          res.writeHead(404, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify({ ok: false, error: 'Todo not found' }));
        }
      } else if (req.url.match(/^\/todos\/(.*)$/) && req.method === 'DELETE') {
        const id = req.url.split('/')[2];
        let data = existsSync(dataPath) ? JSON.parse(fs.readFileSync(dataPath, 'utf8')) : { todos: [] };
        const todoIndex = data.todos.findIndex(t => t.id === id);
        if (todoIndex !== -1) {
          const deletedTodo = data.todos.splice(todoIndex, 1)[0];
          fs.writeFileSync(dataPath, JSON.stringify(data));
          res.writeHead(200, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify({ ok: true, todo: deletedTodo }));
        } else {
          res.writeHead(404, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify({ ok: false, error: 'Todo not found' }));
        }
      } else {
        res.writeHead(404, { 'Content-Type': 'text/plain' });
        res.end('Not Found');
      }
    });
  });

  return server;
}

module.exports = { createServer };"
    }
  ],
  "notes": "Updated src/server.js to use crypto.randomUUID() for generating unique IDs and fixed the issue with EADDRINUSE by ensuring the server does not call listen()."
}
